const input = $input.first().json;
const body = input.body || input;

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

let booking_id = body.booking_id || null;
if (booking_id && !UUID_RE.test(booking_id)) {
  booking_id = null;
}

const payload = {
  gcal_event_id: body.gcal_event_id || null,
  booking_id: booking_id,
  lock_key: body.lock_key || null,
  owner_token: body.owner_token || null,
  reason: String(body.reason || 'manual_rollback').substring(0, 500)
};

if (!payload.gcal_event_id && !payload.booking_id && !payload.lock_key) {
  return [{ json: {
    _valid: false,
    success: false,
    error_code: 'INVALID_INPUT',
    error_message: 'Rollback requires at least one valid ID (gcal_event_id, booking_id, or lock_key)',
    data: null,
    _meta: { source: 'WF6_Rollback_Workflow', timestamp: new Date().toISOString() }
  }}];
}

const b64Reason = Buffer.from(payload.reason).toString('base64');

return [{ json: {
  _valid: true,
  ...payload,
  b64_reason: b64Reason,
  _rollback: {
    initiated_at: new Date().toISOString(),
    steps: { gcal: { success: true, skipped: true }, db: { success: true, skipped: true }, lock: { success: true, skipped: true } }
  }
}}];

// Gate GCal: only pass items with gcal_event_id
const input = $input.first().json;
if (!input.gcal_event_id) return [];
return [{ json: input }];

// Gate GCal Skip: pass items without gcal_event_id
const input = $input.first().json;
if (input.gcal_event_id) return [];
return [{ json: { ...input, _gcal_skipped: true } }];

const input = $input.first().json;
const prev = $('Validate & Prepare').first().json;
const isError = !!input.message;
// 404 is acceptable (idempotency)
const is404 = isError && (input.message.includes('404') || input.message.toLowerCase().includes('not found'));

return [{ json: {
  ...prev,
  _rollback: {
    ...prev._rollback,
    steps: { ...prev._rollback.steps, gcal: { success: !isError || is404, skipped: false, error: isError && !is404 ? input.message : null } }
  }
}}];

// Gate DB: only pass items with booking_id
const input = $input.first().json;
if (!input.booking_id) return [];
return [{ json: input }];

const input = $input.first().json;

if (!input.booking_id) {
  return [{ json: { ...input, _skip_db_cancel: true } }];
}

const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(input.booking_id)) {
  return [{ json: { ...input, _skip_db_cancel: true, _error: 'Invalid booking_id UUID' } }];
}

const reason = (input.reason || 'manual_rollback').replace(/'/g, "''").substring(0, 500);
const query = "UPDATE bookings SET status = 'CANCELLED', cancelled_at = NOW(), cancellation_reason = '" + reason + "' WHERE id = '" + input.booking_id + "'::uuid AND status != 'CANCELLED' RETURNING id;";

return [{ json: { ...input, cancel_query: query } }];

// Gate DB Skip: pass items without booking_id
const input = $input.first().json;
if (input.booking_id) return [];
return [{ json: { ...input, _db_skipped: true } }];

const input = $input.first().json;
const prev = $('Post GCal').first().json;
const isError = !!input.message;
return [{ json: {
  ...prev,
  _rollback: {
    ...prev._rollback,
    steps: { ...prev._rollback.steps, db: { success: !isError, skipped: false, was_updated: !!input.id, error: isError ? input.message : null } }
  }
}}];

// Gate Lock: only pass items with lock_key
const input = $input.first().json;
if (!input.lock_key) return [];
return [{ json: input }];

const input = $input.first().json;

if (!input.lock_key || !input.owner_token) {
  return [{ json: { ...input, _skip_lock_release: true } }];
}

const SAFE_STR_RE = /^[a-zA-Z0-9_-]{1,255}$/;
if (!SAFE_STR_RE.test(input.lock_key) || !SAFE_STR_RE.test(input.owner_token)) {
  return [{ json: { ...input, _skip_lock_release: true, _error: 'Invalid lock_key or owner_token format' } }];
}

const lockKey = input.lock_key.replace(/'/g, "''");
const ownerToken = input.owner_token.replace(/'/g, "''");
const query = "DELETE FROM booking_locks WHERE lock_key = '" + lockKey + "'::text AND owner_token = '" + ownerToken + "'::text RETURNING lock_id;";

return [{ json: { ...input, release_query: query } }];

// Gate Lock Skip: pass items without lock_key
const input = $input.first().json;
if (input.lock_key) return [];
return [{ json: { ...input, _lock_skipped: true } }];

const input = $input.first().json;
const prev = $('Post DB').first().json;
const isError = !!input.message;
return [{ json: {
  ...prev,
  _rollback: {
    ...prev._rollback,
    steps: { ...prev._rollback.steps, lock: { success: !isError, skipped: false, was_released: !!input.lock_id, error: isError ? input.message : null } }
  }
}}];

const rb = $input.first().json._rollback;
const steps = rb.steps;
const hasFailure = !steps.gcal.success || !steps.db.success || !steps.lock.success;

return [{ json: {
  success: !hasFailure,
  error_code: hasFailure ? 'PARTIAL_ROLLBACK_FAILED' : null,
  error_message: hasFailure ? 'Some rollback steps failed' : null,
  data: {
    rollback_completed: !hasFailure,
    steps: steps,
    initiated_at: rb.initiated_at,
    completed_at: new Date().toISOString()
  },
  _meta: { source: 'WF6_Rollback_Workflow', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];

// Gate Valid: only pass valid items to rollback flow
const input = $input.first().json;
if (input._valid !== true) return [];
return [{ json: input }];

// Gate Valid Skip: pass validation errors to output
const input = $input.first().json;
if (input._valid === true) return [];
return [{ json: {
  success: false,
  error_code: input.error_code || 'INVALID_INPUT',
  error_message: input.error_message || 'Invalid rollback input',
  data: null,
  _meta: { source: 'WF6_Rollback_Workflow', timestamp: new Date().toISOString(), workflow_id: $workflow.id }
}}];
